import { useState } from "react";

const ROTATIONS = [-3.2, 2.1, -1.4, 3.5, -2.8, 1.7, -0.9, 2.6, -3.1, 1.3, -2.3, 0.8];

const PHOTOS = [
  { src: "data:image/jpeg;base64,", caption: "encharcados e felizes", date: "01/12/2025" },
  { src: "data:image/jpeg;base64,", caption: "até o Papai Noel quis uma foto com a gente", date: "15/12/2025" },
  { src: "data:image/jpeg;base64,", caption: "sua cara quando viu as luzes", date: "03/12/2025" },
  { src: "data:image/jpeg;base64,", caption: "o melhor começo de ano que eu poderia ter", date: "01/01/2026" },
  { src: "data:image/jpeg;base64,", caption: "esse riso não tem preço", date: "02/01/2026" },
  { src: "data:image/jpeg;base64,", caption: "Balneário lá de cima, nós dois assim", date: "16/01/2026" },
  { src: "data:image/jpeg;base64,", caption: "você olhando pra mim desse jeito", date: "16/01/2026" },
  { src: "data:image/jpeg;base64,", caption: "nem sei como essa foto existe mas amo", date: "12/01/2026" },
  { src: "data:image/jpeg;base64,", caption: "te segurei e não quis mais largar", date: "12/01/2026" },
  { src: "data:image/jpeg;base64,", caption: "ela colocou uma flor na minha cabeça e eu deixei", date: "12/01/2026" },
  { src: "data:image/jpeg;base64,", caption: "o pedido foi aqui, nessa praia, nessa noite", date: "14/01/2026" },
  { src: "data:image/jpeg;base64,", caption: "tiara rosa, argila no rosto, tudo certo", date: "21/01/2026" },
];

const css = `
  @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,400;0,700;1,400&family=Caveat:wght@400;500;600&family=Inter:wght@300;400;500&display=swap');
  *,*::before,*::after{box-sizing:border-box;margin:0;padding:0;}
  :root{
    --rose:#e8637a;--rose-light:#f5a0b0;--rose-dark:#c0415a;
    --gold:#d4a96a;--bg:#0d0a0f;--border:rgba(232,99,122,0.2);
    --text:#f0e6ea;--muted:rgba(240,230,234,0.55);
  }
  .polaroids-section{position:relative;z-index:1;min-height:100vh;display:flex;flex-direction:column;align-items:center;padding:64px 16px 80px;}
  .polaroids-hearts-bg{position:fixed;inset:0;pointer-events:none;z-index:0;overflow:hidden;}
  .polaroids-hf{position:absolute;animation:polaroids-floatUp linear infinite;opacity:0;bottom:-40px;}
  @keyframes polaroids-floatUp{
    0%{transform:translateY(0) rotate(-10deg);opacity:0;}
    10%{opacity:0.18;}90%{opacity:0.08;}
    100%{transform:translateY(-110vh) rotate(10deg);opacity:0;}
  }

  .polaroids-stage{position:relative;z-index:1;min-height:100vh;display:flex;flex-direction:column;align-items:center;padding:72px 20px 100px;}

  .polaroids-hdr{text-align:center;margin-bottom:48px;animation:polaroids-fadeUp 0.8s ease both;}
  @keyframes polaroids-fadeUp{from{opacity:0;transform:translateY(24px);}}
  .polaroids-lbl{text-transform:uppercase;letter-spacing:0.22em;font-size:11px;color:var(--rose-light);margin-bottom:14px;display:block;}
  .polaroids-ttl{font-family:'Playfair Display',serif;font-size:clamp(28px,5.5vw,50px);font-weight:400;line-height:1.2;}
  .polaroids-ttl em{font-style:italic;background:linear-gradient(135deg,var(--rose-light),var(--rose));-webkit-background-clip:text;-webkit-text-fill-color:transparent;}
  .polaroids-sub{color:var(--muted);font-size:13px;margin-top:12px;letter-spacing:0.04em;}
  .polaroids-divd{width:48px;height:1px;background:linear-gradient(90deg,transparent,var(--rose),transparent);margin:18px auto 0;}

  .polaroids-grid{
    display:grid;
    grid-template-columns:repeat(auto-fill,minmax(165px,1fr));
    gap:32px 20px;
    width:100%;max-width:860px;
  }
  @media(max-width:480px){
    .polaroids-grid{grid-template-columns:repeat(2,1fr);gap:24px 14px;}
  }

  /* polaroid outer wrapper — handles the tilt */
  .polaroids-pol-wrap{
    display:flex;flex-direction:column;align-items:center;
    cursor:pointer;
    animation:polaroids-fadeUp 0.6s ease both;
  }

  /* the white polaroid card — padding-bottom creates the white strip */
  .polaroids-pol{
    background:#fff;
    padding: 7px 7px 0 7px; /* sides + top only, bottom handled by .pol-bottom */
    box-shadow:0 6px 24px rgba(0,0,0,0.5),0 2px 8px rgba(0,0,0,0.3);
    width:100%;
    transition:transform 0.3s ease, box-shadow 0.3s ease;
    display:flex;
    flex-direction:column;
  }
  .pol:hover{
    box-shadow:0 16px 48px rgba(0,0,0,0.65),0 4px 16px rgba(232,99,122,0.2) !important;
  }

  /* photo sits flush inside the frame */
  .polaroids-pol-img{
    width:100%;
    aspect-ratio:3/4;
    object-fit:cover;
    display:block;
    flex-shrink:0;
  }
  .polaroids-pol-img.landscape{aspect-ratio:4/3;}

  /* white strip below photo — text lives here, never overlaps */
  .polaroids-pol-bottom{
    background:#fff;
    padding: 6px 4px 8px;
    display:flex;
    flex-direction:column;
    align-items:center;
    gap:1px;
    min-height:44px;
    justify-content:center;
  }
  .polaroids-pol-date{
    font-family:'Caveat',cursive;
    font-size:clamp(10px,2.5vw,13px);
    color:#888;
    text-align:center;
    line-height:1.2;
  }

  /* modal */
  .polaroids-overlay{
    position:fixed;inset:0;z-index:200;
    background:rgba(0,0,0,0.88);
    backdrop-filter:blur(16px);
    display:flex;align-items:center;justify-content:center;
    padding:24px;
    animation:polaroids-fadeIn 0.22s ease;
  }
  @keyframes polaroids-fadeIn{from{opacity:0;}}

  .polaroids-pol-big{
    background:#fff;
    padding:clamp(8px,2.5vw,14px) clamp(8px,2.5vw,14px) 0;
    box-shadow:0 32px 90px rgba(0,0,0,0.8);
    max-width:min(400px,88vw);
    width:100%;
    animation:polaroids-popIn 0.32s cubic-bezier(0.22,1,0.36,1) both;
    position:relative;
    display:flex;
    flex-direction:column;
  }
  @keyframes polaroids-popIn{from{opacity:0;transform:scale(0.8) rotate(-4deg);}}

  .polaroids-pol-big-img{
    width:100%;
    max-height:60vh;
    object-fit:cover;
    display:block;
    flex-shrink:0;
  }

  /* white strip at bottom of expanded polaroid */
  .polaroids-pol-big-bottom{
    background:#fff;
    padding:10px 12px 14px;
    display:flex;
    flex-direction:column;
    align-items:center;
    gap:3px;
  }
  .polaroids-pol-big-caption{
    font-family:'Caveat',cursive;
    font-size:clamp(16px,4.5vw,22px);
    color:#333;
    text-align:center;
    line-height:1.3;
  }
  .polaroids-pol-big-date{
    font-family:'Caveat',cursive;
    font-size:clamp(12px,3vw,15px);
    color:#777;
    text-align:center;
  }
  .polaroids-pol-close{
    position:absolute;top:-14px;right:-14px;
    width:34px;height:34px;border-radius:50%;
    background:var(--rose-dark);
    border:none;cursor:pointer;
    color:#fff;font-size:18px;
    display:flex;align-items:center;justify-content:center;
    box-shadow:0 4px 16px rgba(0,0,0,0.5);
    transition:transform 0.2s,background 0.2s;
    z-index:10;
  }
  .polaroids-pol-close:hover{transform:scale(1.15);background:var(--rose);}

  .polaroids-hint{margin-top:32px;font-size:12px;color:var(--muted);letter-spacing:0.1em;text-align:center;opacity:0.6;animation:polaroids-fadeUp 1s 0.3s ease both;}
`;

const BG_HEARTS = Array.from({length:14},(_,i)=>({
  id:i, left:`${(i*7.3+6)%100}%`,
  delay:`${(i*0.85)%10}s`, dur:`${12+(i%6)}s`,
  size:`${11+(i%8)}px`, emoji:i%3===0?"💕":"❤️",
}));

export default function Polaroids() {
  const [selected, setSelected] = useState<number | null>(null);

  return (
    <section id="s9" className="section polaroids-section">
      <style>{css}</style>
      <div className="polaroids-hearts-bg">
        {BG_HEARTS.map(h=>(
          <span key={h.id} className="polaroids-hf"
            style={{left:h.left,animationDelay:h.delay,animationDuration:h.dur,fontSize:h.size}}>
            {h.emoji}
          </span>
        ))}
      </div>

      <div className="polaroids-stage">
        <div className="polaroids-hdr">
          <span className="polaroids-lbl">❤ para você</span>
          <h2 className="polaroids-ttl">Nossas <em>Fotos</em></h2>
          <div className="polaroids-divd"/>
          <p className="polaroids-sub">as que eu mais amo — exatamente por serem assim</p>
        </div>

        <div className="polaroids-grid">
          {PHOTOS.map((p,i)=>(
            <div key={i} className="polaroids-pol-wrap"
              style={{animationDelay:`${i*0.06}s`}}
              onClick={()=>setSelected(i)}>
              <div className="polaroids-pol" style={{transform:`rotate(${ROTATIONS[i%ROTATIONS.length]}deg)`}}>
                <img
                  className={`polaroids-pol-img${i===2?" landscape":""}`}
                  src={p.src}
                  alt={p.caption}
                  loading="lazy"
                />
                <div className="polaroids-pol-bottom">
                  <div className="polaroids-pol-date">{p.date}</div>
                </div>
              </div>
            </div>
          ))}
        </div>

        <p className="polaroids-hint">toque em uma foto para ver a legenda ✏️</p>
      </div>

      {selected !== null && (
        <div className="polaroids-overlay" onClick={()=>setSelected(null)}>
          <div className="polaroids-pol-big"
            style={{transform:`rotate(${ROTATIONS[selected%ROTATIONS.length] * 0.4}deg)`}}
            onClick={e=>e.stopPropagation()}>
            <button className="polaroids-pol-close" onClick={()=>setSelected(null)}>×</button>
            <img
              className="polaroids-pol-big-img"
              src={PHOTOS[selected].src}
              alt={PHOTOS[selected].caption}
            />
            <div className="polaroids-pol-big-bottom">
              <div className="polaroids-pol-big-caption">{PHOTOS[selected].caption}</div>
              <div className="polaroids-pol-big-date">{PHOTOS[selected].date}</div>
            </div>
          </div>
        </div>
      )}
    </section>
  );
}
